router.delete("/events/past", async (_req, res) => {
  const today = new Date();
  today.setHours(0, 0, 0, 0);
  // Past = COALESCE(dateEnd, dateStart) < today
  const result = await db.delete(eventsTable)
    .where(sql`COALESCE(${eventsTable.dateEnd}, ${eventsTable.dateStart}) < ${today}`)
