router.post("/events/:id/rewrite", async (req, res) => {
  const [event] = await db.select().from(eventsTable).where(eq(eventsTable.id, parseInt(req.params.id))).limit(1);
  if (!event) return res.status(404).json({ error: "Evento non trovato" });
  if (!event.descriptionRaw) return res.status(400).json({ error: "Nessun testo grezzo disponibile" });

  const clean = await claudeRewrite(event.descriptionRaw, event.title, event.location, event.dateDisplay);
  const [updated] = await db.update(eventsTable).set({ descriptionClean: clean, updatedAt: new Date() })
    .where(eq(eventsTable.id, event.id)).returning();
  res.json(updated);
});

router.post("/events/:id/rescrape", async (req, res) => {
  const [event] = await db.select().from(eventsTable).where(eq(eventsTable.id, parseInt(req.params.id))).limit(1);
  if (!event) return res.status(404).json({ error: "Evento non trovato" });
  if (!event.sourceUrl) return res.status(400).json({ error: "Nessun URL sorgente" });

  const settingRow = await db.select().from(settingsTable).where(eq(settingsTable.key, "browseract_single_page_workflow_id")).limit(1);
  const workflowId = settingRow[0]?.value;
  const appBaseUrl = process.env.APP_BASE_URL || `https://${process.env.REPLIT_DEV_DOMAIN}`;

  let taskId: string | undefined;
  if (workflowId) {
    try {
      const result = await triggerBrowserActWorkflow(workflowId, `${appBaseUrl}/api/browseract/webhook/${event.sourceId || 0}/0`);
      taskId = result.taskId;
    } catch {
      // Fall through to Claude fallback
    }
  }

  if (!taskId) {
    const { events } = await claudeFetchAndExtract(event.sourceUrl);
    if (events.length > 0) {
      const raw = events[0] as { description?: string; description_raw?: string };
      const descRaw = raw.description || raw.description_raw || "";
      if (descRaw) {
        const clean = await claudeRewrite(descRaw, event.title, event.location, event.dateDisplay);
        await db.update(eventsTable).set({ descriptionRaw: descRaw, descriptionClean: clean, updatedAt: new Date() })
          .where(eq(eventsTable.id, event.id));
      }
    }
  }

  res.json({ message: "Riscraping avviato", taskId });
});

