  const settingRow = await db.select().from(settingsTable).where(eq(settingsTable.key, "browseract_single_page_workflow_id")).limit(1);
  const workflowId = settingRow[0]?.value;
  const appBaseUrl = process.env.APP_BASE_URL || `https://${process.env.REPLIT_DEV_DOMAIN}`;

  // Try BrowserAct first, fall back to Claude fetch
  try {
    if (workflowId) {
      await triggerBrowserActWorkflow(workflowId, `${appBaseUrl}/api/browseract/webhook/0/0`);
      return res.json({ message: "Estrazione avviata via BrowserAct", sourceUrl: url, dateParseConfidence: "medium", recurring: false });
    }
  } catch { /* fall through */ }

  const { events } = await claudeFetchAndExtract(url);
  if (events.length > 0) {
    const event = events[0] as Record<string, unknown>;
    res.json({
      title: event.title, dateStart: event.date || event.date_start,
      location: event.location, descriptionRaw: event.description || event.description_raw,
      descriptionClean: event.description_clean, category: event.category, price: event.price,
      sourceUrl: url, dateParseConfidence: "medium", recurring: false,
    });
  } else {
    res.json({ sourceUrl: url, dateParseConfidence: "low", recurring: false });
  }
});

export default router;

