import { Router } from "express";
import { db } from "@workspace/db";
import { eventsTable, sourcesTable, settingsTable } from "@workspace/db/schema";
import { eq, and, like, gte, lte, lt, inArray, sql, desc } from "drizzle-orm";
import { requireAuth } from "../middlewares/auth";
import { claudeRewrite, claudeExtractFromText, claudeExtractFromImages, claudeFetchAndExtract } from "../lib/claude";
import { triggerBrowserActWorkflow } from "../lib/browseract";
import { generateDateDisplay, trimDateEndIfMultiWeek } from "../lib/eventProcessing";

const router = Router();
router.use(requireAuth);

router.get("/events", async (req, res) => {
  const { status, sourceId, category, dateFrom, dateTo, search, page = "1", limit = "50" } = req.query as Record<string, string>;
  const pageNum = parseInt(page);
  const limitNum = parseInt(limit);
  const offset = (pageNum - 1) * limitNum;

  let conditions: ReturnType<typeof eq>[] = [];
  if (status) conditions.push(eq(eventsTable.status, status));
  if (sourceId) conditions.push(eq(eventsTable.sourceId, parseInt(sourceId)));
  if (category) conditions.push(eq(eventsTable.category, category));
  if (dateFrom) conditions.push(gte(eventsTable.dateStart, new Date(dateFrom)));
  if (dateTo) conditions.push(lte(eventsTable.dateStart, new Date(dateTo)));
  if (search) conditions.push(like(eventsTable.title, `%${search}%`));

  const where = conditions.length ? and(...conditions) : undefined;
  const [events, [{ count }]] = await Promise.all([
    db.select({
      id: eventsTable.id, sourceId: eventsTable.sourceId, title: eventsTable.title,
      dateStart: eventsTable.dateStart, dateEnd: eventsTable.dateEnd, dateDisplay: eventsTable.dateDisplay,
      dateParseConfidence: eventsTable.dateParseConfidence, recurring: eventsTable.recurring,
      location: eventsTable.location, descriptionRaw: eventsTable.descriptionRaw,
      descriptionClean: eventsTable.descriptionClean, imageUrl: eventsTable.imageUrl,
      sourceUrl: eventsTable.sourceUrl, category: eventsTable.category, price: eventsTable.price,
      status: eventsTable.status, includedInNewsletter: eventsTable.includedInNewsletter,
      sourceType: eventsTable.sourceType, scraper: eventsTable.scraper,
      createdAt: eventsTable.createdAt, sourceName: sourcesTable.name,
    }).from(eventsTable)
      .leftJoin(sourcesTable, eq(eventsTable.sourceId, sourcesTable.id))
      .where(where)
      .orderBy(desc(eventsTable.createdAt))
      .limit(limitNum)
      .offset(offset),
    db.select({ count: sql<number>`count(*)::int` }).from(eventsTable).where(where),
  ]);

  res.json({ events, total: count, page: pageNum, limit: limitNum });
});

