56	          <p className="text-muted-foreground mt-1">Componi ed esporta le newsletter settimanali per Beehiiv.</p>
57	        </div>
58	        <Button onClick={() => setDialogOpen(true)} className="shadow-md">
59	          <Plus className="w-4 h-4 mr-2" />
60	          Nuova Newsletter
61	        </Button>
62	      </div>
63	
64	      {/* Create Dialog */}
65	      <Dialog open={dialogOpen} onOpenChange={setDialogOpen}>
66	        <DialogContent className="sm:max-w-md">
67	          <DialogHeader>
68	            <DialogTitle>Nuova Newsletter</DialogTitle>
69	          </DialogHeader>
70	          <div className="space-y-4 py-2">
71	            <p className="text-sm text-muted-foreground">
72	              Seleziona il periodo di riferimento per gli eventi da includere nella newsletter.
73	            </p>
74	            <Button
75	              variant="outline"
76	              size="sm"
77	              className="w-full gap-2 border-dashed"
78	              onClick={() => {
79	                const today = new Date();
80	                setDateFrom(format(today, 'yyyy-MM-dd'));
81	                setDateTo(format(addDays(today, 6), 'yyyy-MM-dd'));
82	              }}
83	            >
