103	                  onChange={e => setDateTo(e.target.value)}
104	                />
105	              </div>
106	            </div>
107	          </div>
108	          <DialogFooter>
109	            <Button variant="outline" onClick={() => setDialogOpen(false)} disabled={isCreating}>
110	              Annulla
111	            </Button>
112	            <Button onClick={handleCreate} disabled={isCreating}>
113	              {isCreating ? "Creazione..." : "Crea Newsletter"}
114	            </Button>
115	          </DialogFooter>
116	        </DialogContent>
117	      </Dialog>
118	
119	      <div className="bg-card rounded-xl border border-border/50 shadow-sm overflow-hidden">
120	        <div className="overflow-x-auto">
121	          <table className="w-full text-sm text-left">
122	            <thead className="bg-muted/30 text-muted-foreground font-medium border-b border-border/50">
